import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { FaEye, FaEyeSlash } from 'react-icons/fa';
import { Cpu, Terminal, Lock, ShieldCheck } from 'lucide-react';
import toast from 'react-hot-toast';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  const { theme } = useTheme(); 
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('FIELDS_REQUIRED');
    
    const toastId = toast.loading('INITIALIZING_SECURE_HANDSHAKE...');
    setLoading(true);
    try {
      await login(email, password);
      toast.success('ACCESS_GRANTED', { id: toastId });
      navigate('/dashboard'); 
    } catch (err) { 
      toast.error('GATE_REJECTION: INVALID_CREDENTIALS', { id: toastId }); 
    } finally { 
      setLoading(false); 
    }
  };

  const styles = {
    container: { 
      minHeight: '100vh', // Changed to 100vh for true centering
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center', 
      padding: '2rem',
      backgroundColor: 'var(--bg-main, #0a0a0a)' 
    },
    card: { 
      width: '100%', 
      maxWidth: '420px', 
      padding: '2.5rem', 
      backgroundColor: 'var(--card-bg, #111)', 
      borderRadius: '24px', 
      border: '1px solid var(--border-color, #333)', 
      boxShadow: 'var(--shadow-soft, 0 10px 30px rgba(0,0,0,0.5))',
      position: 'relative',
      overflow: 'hidden'
    },
    headerIcon: {
      display: 'flex',
      justifyContent: 'center',
      marginBottom: '1rem',
      color: 'var(--primary-accent, #10b981)'
    },
    title: { 
      fontSize: '1.8rem', 
      color: 'var(--text-main, #fff)', 
      marginBottom: '0.5rem', 
      textAlign: 'center',
      textTransform: 'uppercase',
      letterSpacing: '0.2em',
      fontWeight: '300'
    },
    subtitle: {
      textAlign: 'center',
      fontSize: '10px',
      color: 'var(--text-muted, #666)',
      textTransform: 'uppercase',
      letterSpacing: '0.25em',
      marginBottom: '2rem'
    },
    inputGroup: { 
      position: 'relative', 
      marginBottom: '1.2rem', 
      width: '100%',
      display: 'flex',
      flexDirection: 'column'
    },
    label: {
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      fontSize: '10px',
      color: 'var(--primary-accent, #10b981)',
      fontWeight: 'bold',
      textTransform: 'uppercase',
      letterSpacing: '0.1em',
      marginBottom: '8px',
      paddingLeft: '4px'
    },
    input: { 
      width: '100%', 
      padding: '0.8rem 1rem', 
      paddingRight: '3rem', // Room for the eye icon
      backgroundColor: 'var(--input-bg, #1a1a1a)', 
      border: '1px solid var(--border-color, #333)', 
      borderRadius: '12px', 
      color: 'var(--text-main, #fff)', 
      fontSize: '14px', 
      outline: 'none',
      transition: 'border-color 0.3s ease',
    },
    toggleBtn: { 
      position: 'absolute', 
      right: '12px', 
      bottom: '10px', 
      background: 'none', 
      border: 'none', 
      color: 'var(--text-muted, #666)', 
      cursor: 'pointer', 
      fontSize: '1.1rem',
      zIndex: 10, // Ensure it stays above the input
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center'
    },
    button: { 
      width: '100%', 
      padding: '1rem', 
      marginTop: '1rem', 
      backgroundColor: 'var(--primary-accent, #10b981)', 
      color: '#000', 
      border: 'none', 
      borderRadius: '12px', 
      fontWeight: 'bold',
      textTransform: 'uppercase',
      letterSpacing: '0.2em',
      fontSize: '12px',
      cursor: 'pointer', 
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '10px',
      transition: 'transform 0.2s ease, opacity 0.2s ease',
    },
  };

  return (
    <div style={styles.container}>
      <div style={styles.card} className="reveal-data">
        {/* Laser Scan Decor - Ensure you have this animation in your CSS */}
        <div className="absolute top-0 left-0 w-full h-[2px] bg-emerald-500/50 shadow-[0_0_15px_#10b981] animate-pulse" />
        
        <div style={styles.headerIcon}>
          <Cpu size={42} className="animate-pulse" />
        </div>

        <h2 style={styles.title}>Access_Gate</h2>
        <p style={styles.subtitle}>Node_ID: 8000 // Security_Protocol</p>

        <form onSubmit={handleLogin}>
          <div style={styles.inputGroup}>
            <label style={styles.label} htmlFor="email">
              <Terminal size={12} /> Operator_Email
            </label>
            <input 
              id="email"
              type="email" 
              placeholder="operator@finify.ai" 
              value={email} 
              onChange={(e) => setEmail(e.target.value)} 
              style={styles.input} 
              className="focus:border-emerald-500"
              required
            />
          </div>
          
          <div style={styles.inputGroup}>
            <label style={styles.label} htmlFor="password">
              <Lock size={12} /> Secure_Key
            </label>
            <input 
              id="password"
              type={showPass ? "text" : "password"} 
              placeholder="••••••••" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              style={styles.input} 
              className="focus:border-emerald-500"
              required
            />
            <button 
              type="button" 
              onClick={() => setShowPass(!showPass)} 
              style={styles.toggleBtn}
              tabIndex="-1" // Prevent tabbing into the eye icon for speed
            >
              {showPass ? <FaEyeSlash /> : <FaEye />}
            </button>
          </div>
          
          <button 
            type="submit" 
            style={styles.button} 
            disabled={loading} 
            className="hover:opacity-90 active:scale-95"
          >
            {loading ? 'SYNCHRONIZING...' : <><ShieldCheck size={16}/> Connect_to_Terminal</>}
          </button>
        </form>

        <div style={{
          textAlign: 'center', 
          marginTop: '2rem', 
          paddingTop: '1.5rem', 
          borderTop: '1px solid rgba(255,255,255,0.05)'
        }}>
          <Link to="/register" style={{
            color: 'var(--primary-accent, #10b981)', 
            fontSize: '10px', 
            textTransform: 'uppercase', 
            letterSpacing: '0.1em',
            textDecoration: 'none'
          }}>
            Initialize_New_Identity
          </Link>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
